    }, this), /*#__PURE__*/_jsxDEV("style", {
      children: `
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        :root {
          --blue: #0077b6;
          --cyan: #00d4ff;
          --dark: #0a0f2e;
          --mid: #0d2b5e;
          --white: #ffffff;
          --gray: #f4f7fc;
          --text: #1a2340;
          --muted: #64748b;
          --radius: 14px;
          --ff-head: 'Cinzel', serif;
          --ff-body: 'DM Sans', sans-serif;
        }

        body { font-family: var(--ff-body); background: #f4f7fc; overflow-x: hidden; }

        .page-wrap { position: relative; overflow-x: hidden; }

        /* Watermark Logo */
        .watermark-logo {
          position: fixed;
          bottom: 50%;
          left: 50%;
          transform: translate(-50%, 50%);
          width: 320px;
          opacity: 0.04;
          pointer-events: none;
          z-index: 0;
          animation: wm-float 8s ease-in-out infinite;
        }
        .watermark-logo img { width: 100%; height: auto; filter: grayscale(1); }
        @keyframes wm-float {
          0%,100% { transform: translate(-50%, 50%) scale(1); }
          50% { transform: translate(-50%, 52%) scale(1.04); }
        }

        /* WhatsApp Button */
        .whatsapp-btn {
          position: fixed; bottom: 28px; right: 28px; z-index: 800;
          width: 58px; height: 58px; border-radius: 50%;
          background: #25d366;
          display: flex; align-items: center; justify-content: center;
          color: white; text-decoration: none;
          box-shadow: 0 4px 20px rgba(37,211,102,0.5);
          transition: transform 0.25s, box-shadow 0.25s;
        }
        .whatsapp-btn:hover {
          transform: scale(1.1);
          box-shadow: 0 6px 28px rgba(37,211,102,0.7);
        }
        .whatsapp-btn:hover .wa-tooltip { opacity: 1; transform: translateX(-110%) scale(1); }
        .wa-tooltip {
          position: absolute; right: 66px; background: #25d366;
          color: white; padding: 6px 12px; border-radius: 20px;
          font-size: 13px; white-space: nowrap; font-family: var(--ff-body);
          opacity: 0; transform: translateX(-100%) scale(0.8);
          transition: all 0.2s; pointer-events: none;
        }

        /* Promo Ticker */
        .promo-ticker {
          position: sticky; top: 0; z-index: 600;
          background: linear-gradient(90deg, var(--dark), var(--blue), var(--dark));
          color: white; padding: 8px 0; overflow: hidden;
          font-family: var(--ff-body); font-size: 13px; font-weight: 500;
        }
        .promo-content {
          display: inline-flex; white-space: nowrap;
          animation: promoScroll 28s linear infinite;
        }
        .promo-content:hover { animation-play-state: paused; }
        .ticker-sep { margin: 0 20px; opacity: 0.4; }
        @keyframes promoScroll { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }

        /* Navigation */
        .nav {
          position: sticky; top: 36px; z-index: 500;
          display: flex; justify-content: space-between; align-items: center;
          padding: 12px 40px;
          background: rgba(255,255,255,0.9);
          backdrop-filter: blur(12px);
          border-bottom: 1px solid rgba(0,119,182,0.1);
          box-shadow: 0 2px 20px rgba(0,0,0,0.06);
        }
        .logo-container { display: flex; align-items: center; gap: 12px; }
        .nav-logo-wrap {
          width: 42px; height: 42px; border-radius: 50%;
          background: linear-gradient(135deg, var(--blue), var(--cyan));
          padding: 2px;
          box-shadow: 0 0 12px rgba(0,212,255,0.4);
          animation: logoGlow 3s ease-in-out infinite;
        }
        @keyframes logoGlow {
          0%,100% { box-shadow: 0 0 10px rgba(0,212,255,0.3); }
          50% { box-shadow: 0 0 22px rgba(0,212,255,0.7), 0 0 40px rgba(0,119,182,0.3); }
        }
        .logo { width: 100%; height: 100%; border-radius: 50%; object-fit: cover; }
        .company-name { font-family: var(--ff-head); color: var(--dark); font-size: 18px; letter-spacing: 1px; }
        .nav-links { display: flex; gap: 28px; }
        .nav-link {
          cursor: pointer; color: var(--muted); font-weight: 500; font-size: 14px;
          position: relative; transition: color 0.2s;
        }
        .nav-link::after {
          content: ''; position: absolute; bottom: -3px; left: 0;
          width: 0; height: 2px; background: var(--blue);
          transition: width 0.25s;
        }
        .nav-link:hover { color: var(--blue); }
        .nav-link:hover::after { width: 100%; }

        /* Hero */
        .hero-section {
          position: relative; height: 92vh; min-height: 500px;
          display: flex; align-items: center; justify-content: center;
          overflow: hidden;
        }
        .hero-video-wrap { position: absolute; inset: 0; }
        .hero-video { width: 100%; height: 100%; object-fit: cover; }
        .hero-overlay {
          position: absolute; inset: 0;
          background: linear-gradient(135deg, rgba(10,15,46,0.85) 0%, rgba(0,119,182,0.6) 100%);
        }
        .hero-content {
          position: relative; z-index: 2; text-align: center; padding: 20px;
          opacity: 0; transform: translateY(30px);
          transition: all 1.2s cubic-bezier(0.22, 1, 0.36, 1);
        }
        .hero-content.loaded { opacity: 1; transform: translateY(0); }

        .hero-logo-glow {
          width: 100px; height: 100px; border-radius: 50%; margin: 0 auto 20px;
          background: linear-gradient(135deg, var(--blue), var(--cyan));
          padding: 3px;
          box-shadow: 0 0 30px rgba(0,212,255,0.6), 0 0 60px rgba(0,119,182,0.4);
          animation: heroLogoGlow 2.5s ease-in-out infinite;
        }
        @keyframes heroLogoGlow {
          0%,100% { box-shadow: 0 0 25px rgba(0,212,255,0.5), 0 0 50px rgba(0,119,182,0.3); }
          50% { box-shadow: 0 0 45px rgba(0,212,255,0.9), 0 0 90px rgba(0,119,182,0.6); }
        }
        .hero-logo-glow img {
          width: 100%; height: 100%; border-radius: 50%; object-fit: cover; display: block;
        }

        .hero-title {
          font-family: var(--ff-head); font-size: clamp(28px, 5vw, 52px);
          color: white; line-height: 1.15; margin-bottom: 16px;
          text-shadow: 0 2px 20px rgba(0,0,0,0.3);
        }
        .hero-sub { font-size: 18px; color: rgba(255,255,255,0.82); margin-bottom: 32px; }
        .cta-buttons { display: flex; justify-content: center; gap: 16px; flex-wrap: wrap; }
        .cta {
          padding: 14px 28px; font-size: 15px; font-weight: 600;
          border-radius: 50px; cursor: pointer; transition: all 0.3s;
          font-family: var(--ff-body);
        }
        .cta-primary {
          background: linear-gradient(135deg, var(--blue), var(--cyan));
          color: white; border: none;
          box-shadow: 0 4px 20px rgba(0,119,182,0.5);
        }
        .cta-primary:hover { transform: translateY(-2px); box-shadow: 0 8px 30px rgba(0,119,182,0.7); }
        .cta-outline {
          background: transparent; color: white;
          border: 2px solid rgba(255,255,255,0.6);
        }
        .cta-outline:hover { background: rgba(255,255,255,0.15); border-color: white; }

        /* Stats */
        .stats-section {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
          gap: 1px; background: #e2e8f0;
          box-shadow: 0 4px 30px rgba(0,0,0,0.08);
        }
        .stat-card {
          background: var(--dark);
          padding: 32px 20px; text-align: center;
          display: flex; flex-direction: column; gap: 8px;
        }
        .stat-num {
          font-family: var(--ff-head); font-size: 36px;
          background: linear-gradient(135deg, var(--cyan), #fff);
          -webkit-background-clip: text; -webkit-text-fill-color: transparent;
          background-clip: text;
        }
        .stat-label { color: rgba(255,255,255,0.6); font-size: 13px; letter-spacing: 1px; text-transform: uppercase; }

        /* Sections */
        .section { padding: 80px 40px; position: relative; z-index: 1; }
        .section-title {
          font-family: var(--ff-head); font-size: 28px;
          color: var(--dark); margin-bottom: 10px; text-align: center;
        }
        .section-sub { color: var(--muted); text-align: center; margin-bottom: 40px; }

        /* Service Cards */
        .cards-container {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
          gap: 20px; margin-top: 40px;
        }
        .card {
          padding: 28px 20px; background: white;
          border-radius: var(--radius);
          box-shadow: 0 2px 16px rgba(0,0,0,0.07);
          text-align: center; cursor: pointer;
          transition: transform 0.3s, box-shadow 0.3s;
          opacity: 0; transform: translateY(20px);
          border: 1px solid rgba(0,119,182,0.08);
        }
        .card.loaded { opacity: 1; transform: translateY(0); transition: opacity 0.6s ease, transform 0.6s ease, box-shadow 0.3s; }
        .card:hover { transform: translateY(-6px) scale(1.02); box-shadow: 0 12px 32px rgba(0,119,182,0.15); }
        .card-icon-wrap {
          width: 64px; height: 64px; border-radius: 16px; margin: 0 auto 16px;
          background: linear-gradient(135deg, var(--blue), var(--cyan));
          display: flex; align-items: center; justify-content: center; color: white;
        }
        .card h3 { font-size: 16px; color: var(--dark); margin-bottom: 8px; }
        .card p { font-size: 14px; color: var(--muted); margin-bottom: 12px; }
        .price { font-weight: 700; color: var(--blue); font-size: 15px; }

        /* Pricing */
        .pricing-section { background: linear-gradient(160deg, var(--dark) 0%, var(--mid) 100%); }
        .pricing-section .section-title { color: white; }
        .pricing-section .section-sub { color: rgba(255,255,255,0.5); }
        .pricing-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
          gap: 24px; align-items: center;
        }
        .pricing-card {
          background: rgba(255,255,255,0.05);
          border: 1px solid rgba(255,255,255,0.1);
          border-radius: 20px; padding: 36px 28px;
          text-align: center; transition: transform 0.3s;
          position: relative; overflow: hidden;
        }
        .pricing-card:hover { transform: translateY(-4px); }
        .pricing-card.popular {
          background: linear-gradient(135deg, rgba(0,119,182,0.4), rgba(0,212,255,0.2));
          border-color: var(--cyan);
          transform: scale(1.04);
          box-shadow: 0 8px 40px rgba(0,212,255,0.25);
        }
        .popular-badge {
          position: absolute; top: 14px; right: -26px;
          background: linear-gradient(90deg, var(--blue), var(--cyan));
          color: white; font-size: 11px; font-weight: 700;
          padding: 4px 36px; transform: rotate(40deg);
          letter-spacing: 1px;
        }
        .plan-name { font-family: var(--ff-head); color: white; font-size: 20px; margin-bottom: 16px; }
        .plan-price { margin-bottom: 24px; }
        .plan-amount {
          font-size: 40px; font-weight: 800; color: var(--cyan);
          font-family: var(--ff-head);
        }
        .plan-period { color: rgba(255,255,255,0.4); font-size: 14px; }
        .plan-features { list-style: none; margin-bottom: 28px; }
        .plan-features li {
          color: rgba(255,255,255,0.75); font-size: 14px;
          padding: 7px 0; border-bottom: 1px solid rgba(255,255,255,0.07);
          display: flex; align-items: center; gap: 8px; text-align: left;
        }
        .check { color: var(--cyan); font-size: 14px; flex-shrink: 0; }
        .plan-btn {
          width: 100%; padding: 12px;
          border-radius: 50px; border: 2px solid rgba(255,255,255,0.3);
          background: transparent; color: white;
          font-weight: 600; cursor: pointer; transition: all 0.3s;
          font-family: var(--ff-body); font-size: 14px;
        }
        .plan-btn:hover { background: rgba(255,255,255,0.1); border-color: white; }
        .plan-btn-pop {
          background: linear-gradient(135deg, var(--blue), var(--cyan));
          border-color: transparent;
