import { useNavigate } from "react-router-dom";
import { FaTshirt, FaSprayCan, FaSyncAlt, FaTruck, FaWhatsapp, FaFacebook, FaInstagram, FaTwitter, FaTiktok, FaMapMarkerAlt, FaPhone, FaEnvelope } from "react-icons/fa";
import { useEffect, useState, useRef } from "react";

// ── Splash Screen ─────────────────────────────────────────────────────────────
function SplashScreen({ onDone }) {
  const [fade, setFade] = useState(false);
  useEffect(() => {
    const t1 = setTimeout(() => setFade(true), 2000);
    const t2 = setTimeout(onDone, 2600);
    return () => { clearTimeout(t1); clearTimeout(t2); };
  }, [onDone]);

  return (
    <div className={`splash ${fade ? "splash-fade" : ""}`}>
      <div className="splash-inner">
        <div className="splash-logo-ring">
          <img src="data:image/png;base64," alt="Logo" className="splash-logo" />
        </div>
        <h1 className="splash-title">Deep Citadel</h1>
        <p className="splash-sub">Enterprise Laundry & Delivery</p>
        <div className="splash-bar"><div className="splash-progress" /></div>
      </div>
      <style>{`
        .splash {
          position: fixed; inset: 0; z-index: 9999;
          background: linear-gradient(135deg, #0a0f2e 0%, #0d2b5e 60%, #0077b6 100%);
          display: flex; align-items: center; justify-content: center;
          transition: opacity 0.6s ease;
        }
        .splash-fade { opacity: 0; pointer-events: none; }
        .splash-inner { text-align: center; }
        .splash-logo-ring {
          width: 110px; height: 110px; border-radius: 50%;
          border: 3px solid transparent;
          background: linear-gradient(#0a0f2e, #0a0f2e) padding-box,
                      linear-gradient(90deg, #00d4ff, #0077b6, #00d4ff) border-box;
          display: flex; align-items: center; justify-content: center;
          margin: 0 auto 16px;
          animation: glowRing 2s ease-in-out infinite;
          box-shadow: 0 0 30px rgba(0,212,255,0.5), 0 0 60px rgba(0,119,182,0.3);
        }
        @keyframes glowRing {
          0%,100% { box-shadow: 0 0 20px rgba(0,212,255,0.4), 0 0 50px rgba(0,119,182,0.2); }
          50% { box-shadow: 0 0 40px rgba(0,212,255,0.8), 0 0 80px rgba(0,119,182,0.5); }
        }
        .splash-logo { width: 75px; height: 75px; border-radius: 50%; object-fit: cover; }
        .splash-title { color: #fff; font-size: 28px; font-family: 'Cinzel', serif; letter-spacing: 3px; margin: 0; }
        .splash-sub { color: #00d4ff; font-size: 14px; letter-spacing: 2px; margin: 8px 0 20px; font-family: 'DM Sans', sans-serif; }
        .splash-bar { width: 200px; height: 3px; background: rgba(255,255,255,0.1); border-radius: 2px; margin: 0 auto; overflow: hidden; }
        .splash-progress { height: 100%; background: linear-gradient(90deg, #00d4ff, #0077b6); border-radius: 2px; animation: loadBar 2s ease forwards; width: 0; }
        @keyframes loadBar { to { width: 100%; } }
      `}</style>
    </div>
  );
}

// ── Animated Counter ──────────────────────────────────────────────────────────
function Counter({ target, suffix = "", label }) {
  const [count, setCount] = useState(0);
  const ref = useRef(null);
  const started = useRef(false);

  useEffect(() => {
    const observer = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting && !started.current) {
        started.current = true;
        let start = 0;
        const step = Math.ceil(target / 80);
        const timer = setInterval(() => {
          start += step;
          if (start >= target) { setCount(target); clearInterval(timer); }
          else setCount(start);
        }, 20);
      }
    }, { threshold: 0.5 });
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, [target]);

  return (
    <div ref={ref} className="stat-card">
      <span className="stat-num">{count.toLocaleString()}{suffix}</span>
      <span className="stat-label">{label}</span>
    </div>
  );
}

// ── Main Home Component ───────────────────────────────────────────────────────
export default function Home() {
  const navigate = useNavigate();
  const [loaded, setLoaded] = useState(false);
  const [splash, setSplash] = useState(true);

  useEffect(() => {
    const t = setTimeout(() => setLoaded(true), 2800);
    return () => clearTimeout(t);
  }, []);

  // Favicon injection
  useEffect(() => {
    const link = document.querySelector("link[rel~='icon']") || document.createElement("link");
    link.type = "image/x-icon";
    link.rel = "shortcut icon";
    link.href = "data:image/png;base64,";
    document.getElementsByTagName("head")[0].appendChild(link);
  }, []);

  const services = [
    { title: "Wash & Fold", description: "Quick and affordable wash & fold service", price: "GHS 15/kg", Icon: FaTshirt },
    { title: "Dry Cleaning", description: "Professional dry cleaning for delicate fabrics", price: "GHS 25/item", Icon: FaSprayCan },
    { title: "Ironing", description: "Crisp ironing service for all clothes", price: "GHS 5/item", Icon: FaSyncAlt },
    { title: "Express Delivery", description: "Fast delivery to your doorstep", price: "GHS 10/delivery", Icon: FaTruck },
  ];

  const testimonials = [
    { name: "Ama Mensah", feedback: "Excellent service! My clothes came back perfectly clean and neatly folded.", stars: 5 },
    { name: "Kwame Asante", feedback: "Fast, reliable, and very friendly staff. Will definitely use again!", stars: 5 },
    { name: "Abena Osei", feedback: "The express delivery is a game changer. Saved me so much time.", stars: 5 },
  ];

  const promotions = [
    "🎉 Get 20% off on Wash & Fold this week!",
    "🚚 Free express delivery for orders above GHS 200!",
    "✨ New Dry Cleaning packages available!",
    "📲 Book via WhatsApp and get 10% off!",
  ];

  const pricingPlans = [
    {
      name: "Basic",
      price: "GHS 80",
      period: "/month",
      features: ["Up to 5kg Wash & Fold", "2 Ironing items", "Standard Delivery", "Email Support"],
      color: "#0077b6",
      popular: false,
    },
    {
      name: "Pro",
      price: "GHS 180",
      period: "/month",
      features: ["Up to 15kg Wash & Fold", "10 Ironing items", "2 Dry Clean items", "Express Delivery", "Priority Support"],
      color: "#00d4ff",
      popular: true,
    },
    {
      name: "Business",
      price: "GHS 350",
      period: "/month",
      features: ["Unlimited Wash & Fold", "Unlimited Ironing", "5 Dry Clean items/week", "Free Express Delivery", "Dedicated Agent", "Invoice Billing"],
      color: "#023e8a",
      popular: false,
    },
  ];

  const scrollToSection = (id) => document.getElementById(id)?.scrollIntoView({ behavior: "smooth" });
  const handleSubscribe = (e) => { e.preventDefault(); alert("Thank you for subscribing!"); };
  const logoUrl = "data:image/png;base64,";

  return (
    <>
      {splash && <SplashScreen onDone={() => setSplash(false)} />}

      {/* Google Fonts */}
      <link href="https://fonts.googleapis.com/css2?family=Cinzel:wght@700;900&family=DM+Sans:wght@300;400;500;600&display=swap" rel="stylesheet" />

      <div className="page-wrap">

        {/* Sticky Watermark Logo */}
        <div className="watermark-logo" aria-hidden="true">
          <img src={logoUrl} alt="" />
        </div>

        {/* WhatsApp Floating Button */}
        <a
          href="https://wa.me/+233244639002?text=Hello%2C%20I%20would%20like%20to%20book%20a%20laundry%20service"
          target="_blank"
          rel="noopener noreferrer"
          className="whatsapp-btn"
          aria-label="Chat on WhatsApp"
        >
          <FaWhatsapp size={28} />
          <span className="wa-tooltip">Chat with us!</span>
        </a>

        {/* Promo Ticker */}
        <div className="promo-ticker">
          <div className="promo-content">
            {[...promotions, ...promotions].map((p, i) => (
              <span key={i}>{p}<span className="ticker-sep">•</span></span>
            ))}
          </div>
        </div>

        {/* Navigation */}
        <nav className="nav">
          <div className="logo-container">
            <div className="nav-logo-wrap">
              <img src={logoUrl} alt="Deep Citadel Logo" className="logo" />
            </div>
            <span className="company-name">Deep Citadel</span>
          </div>
          <div className="nav-links">
            {["services", "pricing", "testimonials", "contact"].map(s => (
              <span key={s} className="nav-link" onClick={() => scrollToSection(s)}>
                {s.charAt(0).toUpperCase() + s.slice(1)}
              </span>
            ))}
          </div>
        </nav>

        {/* Hero with Video Background */}
        <section className="hero-section">
          <div className="hero-video-wrap">
            <video autoPlay muted loop playsInline className="hero-video"
              poster="https://images.unsplash.com/photo-1582735689369-4fe89db7114c?w=1400&q=80">
              <source src="https://www.youtube.com/watch?v=oLUrAKdG8SM" type="video/mp4" />
            </video>
            <div className="hero-overlay" />
          </div>
          <div className={`hero-content ${loaded ? "loaded" : ""}`}>
            <div className="hero-logo-glow">
              <img src={logoUrl} alt="Deep Citadel" />
            </div>
            <h1 className="hero-title">Smart Laundry &<br />Delivery Service</h1>
            <p className="hero-sub">Book pickup, track orders, and pay online — all in one place!</p>
            <div className="cta-buttons">
              <button className="cta cta-primary" onClick={() => navigate("/schedule")}>
                Schedule Pickup
              </button>
              <button className="cta cta-outline" onClick={() => navigate("/dashboard")}>
                View Dashboard
              </button>
            </div>
          </div>
        </section>

        {/* Animated Stats */}
        <section className="stats-section">
          <Counter target={1240} suffix="+" label="Jobs Completed" />
          <Counter target={850} suffix="+" label="Happy Customers" />
          <Counter target={3600} suffix="+" label="Deliveries Made" />
          <Counter target={99} suffix="%" label="Satisfaction Rate" />
        </section>

        {/* Services */}
        <section id="services" className="section">
          <h2 className="section-title">Our Services</h2>
          <div className="cards-container">
            {services.map((s, i) => (
              <div key={i} className={`card ${loaded ? "loaded" : ""}`} style={{ animationDelay: `${i * 0.1}s` }}>
                <div className="card-icon-wrap">
                  <s.Icon size={32} />
                </div>
                <h3>{s.title}</h3>
                <p>{s.description}</p>
                <span className="price">{s.price}</span>
              </div>
            ))}
          </div>
        </section>

        {/* Pricing Table */}
        <section id="pricing" className="section pricing-section">
          <h2 className="section-title">Pricing Plans</h2>
          <p className="section-sub">Choose a plan that works for you</p>
          <div className="pricing-grid">
            {pricingPlans.map((plan, i) => (
              <div key={i} className={`pricing-card ${plan.popular ? "popular" : ""}`}>
                {plan.popular && <div className="popular-badge">Most Popular</div>}
                <h3 className="plan-name">{plan.name}</h3>
                <div className="plan-price">
                  <span className="plan-amount">{plan.price}</span>
                  <span className="plan-period">{plan.period}</span>
                </div>
                <ul className="plan-features">
                  {plan.features.map((f, j) => (
                    <li key={j}><span className="check">✓</span>{f}</li>
                  ))}
                </ul>
                <button className={`plan-btn ${plan.popular ? "plan-btn-pop" : ""}`}
                  onClick={() => navigate("/schedule")}>
                  Get Started
                </button>
              </div>
            ))}
          </div>
        </section>

        {/* Testimonials */}
        <section id="testimonials" className="section">
          <h2 className="section-title">What Our Customers Say</h2>
          <div className="testimonials">
            {testimonials.map((t, i) => (
              <div key={i} className={`testimonial-card ${loaded ? "loaded" : ""}`}>
                <div className="stars">{"★".repeat(t.stars)}</div>
                <p>"{t.feedback}"</p>
                <strong>— {t.name}</strong>
              </div>
            ))}
          </div>
        </section>

        {/* Contact / Subscribe */}
        <section id="contact" className="section contact-section-wrap">
          <h2 className="section-title">Stay Updated</h2>
          <p className="section-sub">Subscribe to get exclusive deals and updates</p>
          <form className="contact-form" onSubmit={handleSubscribe}>
            <input type="email" placeholder="Enter your email address" required />
            <button type="submit">Subscribe</button>
          </form>
        </section>

        {/* Footer */}
        <footer className="footer">
          <div className="footer-top">
            <div className="footer-brand">
              <div className="footer-logo-wrap">
                <img src={logoUrl} alt="Deep Citadel" className="footer-logo" />
              </div>
              <div>
                <h3 className="footer-company">Deep Citadel Enterprise</h3>
                <p className="footer-tagline">Clean clothes. Delivered fast.</p>
              </div>
            </div>
            <div className="footer-links">
              <h4>Quick Links</h4>
              <a onClick={() => scrollToSection("services")}>Services</a>
              <a onClick={() => scrollToSection("pricing")}>Pricing</a>
              <a onClick={() => scrollToSection("testimonials")}>Reviews</a>
              <a onClick={() => navigate("/schedule")}>Book Now</a>
            </div>
            <div className="footer-contact-info">
              <h4>Contact</h4>
              <p><FaMapMarkerAlt /> Location— Community 1 Site 17, Tema.Oninku street</p>
              <p><FaPhone /> +233 24 463 9002</p>
              <p><FaEnvelope />deepcitadelent@gmail.com</p>
            </div>
            <div className="footer-social">
              <h4>Follow Us</h4>
              <div className="social-icons">
                <a href="#" aria-label="Facebook"><FaFacebook /></a>
                <a href="#" aria-label="Instagram"><FaInstagram /></a>
                <a href="#" aria-label="Twitter"><FaTwitter /></a>
                <a href="#" aria-label="TikTok"><FaTiktok /></a>
                <a href="https://wa.me/+233244639002" aria-label="WhatsApp"><FaWhatsapp /></a>
              </div>
            </div>
          </div>
          <div className="footer-bottom">
            <p>© {new Date().getFullYear()} Deep Citadel Enterprise. All rights reserved.</p>
          </div>
        </footer>
      </div>

      {/* ── All CSS ─────────────────────────────────────────────────────────── */}
      <style>{`
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        :root {
          --blue: #0077b6;
          --cyan: #00d4ff;
          --dark: #0a0f2e;
          --mid: #0d2b5e;
          --white: #ffffff;
          --gray: #f4f7fc;
          --text: #1a2340;
          --muted: #64748b;
          --radius: 14px;
          --ff-head: 'Cinzel', serif;
          --ff-body: 'DM Sans', sans-serif;
        }

        body { font-family: var(--ff-body); background: #f4f7fc; overflow-x: hidden; }

        .page-wrap { position: relative; overflow-x: hidden; }

        /* Watermark Logo */
        .watermark-logo {
          position: fixed;
          bottom: 50%;
          left: 50%;
          transform: translate(-50%, 50%);
          width: 320px;
          opacity: 0.04;
          pointer-events: none;
          z-index: 0;
          animation: wm-float 8s ease-in-out infinite;
        }
        .watermark-logo img { width: 100%; height: auto; filter: grayscale(1); }
        @keyframes wm-float {
          0%,100% { transform: translate(-50%, 50%) scale(1); }
          50% { transform: translate(-50%, 52%) scale(1.04); }
        }

        /* WhatsApp Button */
        .whatsapp-btn {
          position: fixed; bottom: 28px; right: 28px; z-index: 800;
          width: 58px; height: 58px; border-radius: 50%;
          background: #25d366;
          display: flex; align-items: center; justify-content: center;
          color: white; text-decoration: none;
          box-shadow: 0 4px 20px rgba(37,211,102,0.5);
          transition: transform 0.25s, box-shadow 0.25s;
        }
        .whatsapp-btn:hover {
          transform: scale(1.1);
          box-shadow: 0 6px 28px rgba(37,211,102,0.7);
        }
        .whatsapp-btn:hover .wa-tooltip { opacity: 1; transform: translateX(-110%) scale(1); }
        .wa-tooltip {
          position: absolute; right: 66px; background: #25d366;
          color: white; padding: 6px 12px; border-radius: 20px;
          font-size: 13px; white-space: nowrap; font-family: var(--ff-body);
          opacity: 0; transform: translateX(-100%) scale(0.8);
          transition: all 0.2s; pointer-events: none;
        }

        /* Promo Ticker */
        .promo-ticker {
          position: sticky; top: 0; z-index: 600;
          background: linear-gradient(90deg, var(--dark), var(--blue), var(--dark));
          color: white; padding: 8px 0; overflow: hidden;
          font-family: var(--ff-body); font-size: 13px; font-weight: 500;
        }
        .promo-content {
          display: inline-flex; white-space: nowrap;
          animation: promoScroll 28s linear infinite;
        }
        .promo-content:hover { animation-play-state: paused; }
        .ticker-sep { margin: 0 20px; opacity: 0.4; }
        @keyframes promoScroll { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }

        /* Navigation */
        .nav {
          position: sticky; top: 36px; z-index: 500;
          display: flex; justify-content: space-between; align-items: center;
          padding: 12px 40px;
          background: rgba(255,255,255,0.9);
          backdrop-filter: blur(12px);
          border-bottom: 1px solid rgba(0,119,182,0.1);
          box-shadow: 0 2px 20px rgba(0,0,0,0.06);
        }
        .logo-container { display: flex; align-items: center; gap: 12px; }
        .nav-logo-wrap {
          width: 42px; height: 42px; border-radius: 50%;
          background: linear-gradient(135deg, var(--blue), var(--cyan));
          padding: 2px;
          box-shadow: 0 0 12px rgba(0,212,255,0.4);
          animation: logoGlow 3s ease-in-out infinite;
        }
        @keyframes logoGlow {
          0%,100% { box-shadow: 0 0 10px rgba(0,212,255,0.3); }
          50% { box-shadow: 0 0 22px rgba(0,212,255,0.7), 0 0 40px rgba(0,119,182,0.3); }
        }
        .logo { width: 100%; height: 100%; border-radius: 50%; object-fit: cover; }
        .company-name { font-family: var(--ff-head); color: var(--dark); font-size: 18px; letter-spacing: 1px; }
        .nav-links { display: flex; gap: 28px; }
        .nav-link {
          cursor: pointer; color: var(--muted); font-weight: 500; font-size: 14px;
          position: relative; transition: color 0.2s;
        }
        .nav-link::after {
          content: ''; position: absolute; bottom: -3px; left: 0;
          width: 0; height: 2px; background: var(--blue);
          transition: width 0.25s;
        }
        .nav-link:hover { color: var(--blue); }
        .nav-link:hover::after { width: 100%; }

        /* Hero */
        .hero-section {
          position: relative; height: 92vh; min-height: 500px;
          display: flex; align-items: center; justify-content: center;
          overflow: hidden;
        }
        .hero-video-wrap { position: absolute; inset: 0; }
        .hero-video { width: 100%; height: 100%; object-fit: cover; }
        .hero-overlay {
          position: absolute; inset: 0;
          background: linear-gradient(135deg, rgba(10,15,46,0.85) 0%, rgba(0,119,182,0.6) 100%);
        }
        .hero-content {
          position: relative; z-index: 2; text-align: center; padding: 20px;
          opacity: 0; transform: translateY(30px);
          transition: all 1.2s cubic-bezier(0.22, 1, 0.36, 1);
        }
        .hero-content.loaded { opacity: 1; transform: translateY(0); }

        .hero-logo-glow {
          width: 100px; height: 100px; border-radius: 50%; margin: 0 auto 20px;
          background: linear-gradient(135deg, var(--blue), var(--cyan));
          padding: 3px;
          box-shadow: 0 0 30px rgba(0,212,255,0.6), 0 0 60px rgba(0,119,182,0.4);
          animation: heroLogoGlow 2.5s ease-in-out infinite;
        }
        @keyframes heroLogoGlow {
          0%,100% { box-shadow: 0 0 25px rgba(0,212,255,0.5), 0 0 50px rgba(0,119,182,0.3); }
          50% { box-shadow: 0 0 45px rgba(0,212,255,0.9), 0 0 90px rgba(0,119,182,0.6); }
        }
        .hero-logo-glow img {
          width: 100%; height: 100%; border-radius: 50%; object-fit: cover; display: block;
        }

        .hero-title {
          font-family: var(--ff-head); font-size: clamp(28px, 5vw, 52px);
          color: white; line-height: 1.15; margin-bottom: 16px;
          text-shadow: 0 2px 20px rgba(0,0,0,0.3);
        }
        .hero-sub { font-size: 18px; color: rgba(255,255,255,0.82); margin-bottom: 32px; }
        .cta-buttons { display: flex; justify-content: center; gap: 16px; flex-wrap: wrap; }
        .cta {
          padding: 14px 28px; font-size: 15px; font-weight: 600;
          border-radius: 50px; cursor: pointer; transition: all 0.3s;
          font-family: var(--ff-body);
        }
        .cta-primary {
          background: linear-gradient(135deg, var(--blue), var(--cyan));
          color: white; border: none;
          box-shadow: 0 4px 20px rgba(0,119,182,0.5);
        }
        .cta-primary:hover { transform: translateY(-2px); box-shadow: 0 8px 30px rgba(0,119,182,0.7); }
        .cta-outline {
          background: transparent; color: white;
          border: 2px solid rgba(255,255,255,0.6);
        }
        .cta-outline:hover { background: rgba(255,255,255,0.15); border-color: white; }

        /* Stats */
        .stats-section {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
          gap: 1px; background: #e2e8f0;
          box-shadow: 0 4px 30px rgba(0,0,0,0.08);
        }
        .stat-card {
          background: var(--dark);
          padding: 32px 20px; text-align: center;
          display: flex; flex-direction: column; gap: 8px;
        }
        .stat-num {
          font-family: var(--ff-head); font-size: 36px;
          background: linear-gradient(135deg, var(--cyan), #fff);
          -webkit-background-clip: text; -webkit-text-fill-color: transparent;
          background-clip: text;
        }
        .stat-label { color: rgba(255,255,255,0.6); font-size: 13px; letter-spacing: 1px; text-transform: uppercase; }

        /* Sections */
        .section { padding: 80px 40px; position: relative; z-index: 1; }
        .section-title {
          font-family: var(--ff-head); font-size: 28px;
          color: var(--dark); margin-bottom: 10px; text-align: center;
        }
        .section-sub { color: var(--muted); text-align: center; margin-bottom: 40px; }

        /* Service Cards */
        .cards-container {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
          gap: 20px; margin-top: 40px;
        }
        .card {
          padding: 28px 20px; background: white;
          border-radius: var(--radius);
          box-shadow: 0 2px 16px rgba(0,0,0,0.07);
          text-align: center; cursor: pointer;
          transition: transform 0.3s, box-shadow 0.3s;
          opacity: 0; transform: translateY(20px);
          border: 1px solid rgba(0,119,182,0.08);
        }
        .card.loaded { opacity: 1; transform: translateY(0); transition: opacity 0.6s ease, transform 0.6s ease, box-shadow 0.3s; }
        .card:hover { transform: translateY(-6px) scale(1.02); box-shadow: 0 12px 32px rgba(0,119,182,0.15); }
        .card-icon-wrap {
          width: 64px; height: 64px; border-radius: 16px; margin: 0 auto 16px;
          background: linear-gradient(135deg, var(--blue), var(--cyan));
          display: flex; align-items: center; justify-content: center; color: white;
        }
        .card h3 { font-size: 16px; color: var(--dark); margin-bottom: 8px; }
        .card p { font-size: 14px; color: var(--muted); margin-bottom: 12px; }
        .price { font-weight: 700; color: var(--blue); font-size: 15px; }

        /* Pricing */
        .pricing-section { background: linear-gradient(160deg, var(--dark) 0%, var(--mid) 100%); }
        .pricing-section .section-title { color: white; }
        .pricing-section .section-sub { color: rgba(255,255,255,0.5); }
        .pricing-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
          gap: 24px; align-items: center;
        }
        .pricing-card {
          background: rgba(255,255,255,0.05);
          border: 1px solid rgba(255,255,255,0.1);
          border-radius: 20px; padding: 36px 28px;
          text-align: center; transition: transform 0.3s;
          position: relative; overflow: hidden;
        }
        .pricing-card:hover { transform: translateY(-4px); }
        .pricing-card.popular {
          background: linear-gradient(135deg, rgba(0,119,182,0.4), rgba(0,212,255,0.2));
          border-color: var(--cyan);
          transform: scale(1.04);
          box-shadow: 0 8px 40px rgba(0,212,255,0.25);
        }
        .popular-badge {
          position: absolute; top: 14px; right: -26px;
          background: linear-gradient(90deg, var(--blue), var(--cyan));
          color: white; font-size: 11px; font-weight: 700;
          padding: 4px 36px; transform: rotate(40deg);
          letter-spacing: 1px;
        }
        .plan-name { font-family: var(--ff-head); color: white; font-size: 20px; margin-bottom: 16px; }
        .plan-price { margin-bottom: 24px; }
        .plan-amount {
          font-size: 40px; font-weight: 800; color: var(--cyan);
          font-family: var(--ff-head);
        }
        .plan-period { color: rgba(255,255,255,0.4); font-size: 14px; }
        .plan-features { list-style: none; margin-bottom: 28px; }
        .plan-features li {
          color: rgba(255,255,255,0.75); font-size: 14px;
          padding: 7px 0; border-bottom: 1px solid rgba(255,255,255,0.07);
          display: flex; align-items: center; gap: 8px; text-align: left;
        }
        .check { color: var(--cyan); font-size: 14px; flex-shrink: 0; }
        .plan-btn {
          width: 100%; padding: 12px;
          border-radius: 50px; border: 2px solid rgba(255,255,255,0.3);
          background: transparent; color: white;
          font-weight: 600; cursor: pointer; transition: all 0.3s;
          font-family: var(--ff-body); font-size: 14px;
        }
        .plan-btn:hover { background: rgba(255,255,255,0.1); border-color: white; }
        .plan-btn-pop {
          background: linear-gradient(135deg, var(--blue), var(--cyan));
          border-color: transparent;
          box-shadow: 0 4px 20px rgba(0,212,255,0.4);
        }
        .plan-btn-pop:hover { box-shadow: 0 8px 30px rgba(0,212,255,0.6); transform: translateY(-1px); }

        /* Testimonials */
        .testimonials {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
          gap: 20px; margin-top: 40px;
        }
        .testimonial-card {
          padding: 28px; background: white; border-radius: var(--radius);
          box-shadow: 0 2px 16px rgba(0,0,0,0.06);
          opacity: 0; transform: translateY(20px);
          transition: all 0.7s ease; border-left: 4px solid var(--blue);
        }
        .testimonial-card.loaded { opacity: 1; transform: translateY(0); }
        .stars { color: #f59e0b; font-size: 18px; margin-bottom: 12px; }
        .testimonial-card p { font-style: italic; color: var(--muted); margin-bottom: 12px; font-size: 14px; }
        .testimonial-card strong { color: var(--dark); font-size: 14px; }

        /* Contact */
        .contact-section-wrap { background: var(--gray); text-align: center; }
        .contact-form {
          display: flex; gap: 12px; max-width: 480px; margin: 0 auto;
          flex-wrap: wrap; justify-content: center;
        }
        .contact-form input {
          flex: 1; min-width: 200px; padding: 13px 18px;
          border-radius: 50px; border: 1px solid #d0dce8;
          font-size: 14px; font-family: var(--ff-body);
          outline: none; transition: border-color 0.2s;
        }
        .contact-form input:focus { border-color: var(--blue); }
        .contact-form button {
          padding: 13px 28px; border-radius: 50px;
          background: linear-gradient(135deg, var(--blue), var(--cyan));
          color: white; border: none; font-weight: 600; cursor: pointer;
          font-family: var(--ff-body); transition: all 0.3s;
        }
        .contact-form button:hover { transform: translateY(-2px); box-shadow: 0 6px 20px rgba(0,119,182,0.4); }

        /* Footer */
        .footer {
          background: var(--dark);
          color: rgba(255,255,255,0.7);
          font-family: var(--ff-body);
        }
        .footer-top {
          display: grid;
          grid-template-columns: 2fr 1fr 1.5fr 1fr;
          gap: 40px; padding: 60px 40px 40px;
        }
        @media (max-width: 768px) {
          .footer-top { grid-template-columns: 1fr 1fr; gap: 30px; }
          .nav { padding: 12px 20px; }
          .nav-links { gap: 14px; }
          .section { padding: 60px 20px; }
          .hero-section { height: 80vh; }
        }
        .footer-brand { display: flex; gap: 14px; align-items: flex-start; grid-column: 1; }
        .footer-logo-wrap {
          width: 50px; height: 50px; border-radius: 50%; flex-shrink: 0;
          background: linear-gradient(135deg, var(--blue), var(--cyan));
          padding: 2px;
          animation: logoGlow 3s ease-in-out infinite;
        }
        .footer-logo { width: 100%; height: 100%; border-radius: 50%; object-fit: cover; }
        .footer-company { color: white; font-family: var(--ff-head); font-size: 16px; letter-spacing: 1px; }
        .footer-tagline { font-size: 13px; margin-top: 4px; color: rgba(255,255,255,0.4); }
        .footer h4 { color: white; font-size: 13px; letter-spacing: 2px; text-transform: uppercase; margin-bottom: 16px; }
        .footer-links { display: flex; flex-direction: column; gap: 8px; }
        .footer-links a { cursor: pointer; font-size: 14px; transition: color 0.2s; }
        .footer-links a:hover { color: var(--cyan); }
        .footer-contact-info { display: flex; flex-direction: column; gap: 10px; }
        .footer-contact-info p { font-size: 13px; display: flex; align-items: center; gap: 8px; }
        .footer-contact-info svg { color: var(--cyan); flex-shrink: 0; }
        .social-icons { display: flex; gap: 14px; flex-wrap: wrap; }
        .social-icons a {
          width: 38px; height: 38px; border-radius: 50%;
          background: rgba(255,255,255,0.08); display: flex; align-items: center; justify-content: center;
          color: white; font-size: 16px; transition: all 0.3s; text-decoration: none;
        }
        .social-icons a:hover { background: var(--blue); transform: translateY(-2px); }
        .footer-bottom {
          border-top: 1px solid rgba(255,255,255,0.08);
          padding: 20px 40px; text-align: center;
          font-size: 13px; color: rgba(255,255,255,0.3);
        }
      `}</style>
    </>
  );
}
